parameters.jsonBody:
={
  "model": "mistral-small-latest",
  "messages": [
    {
      "role": "system",
      "content": "You are a medical clinic name correction AI. A voice system misheard a patient name. Given the misheard ASR text and whether it is a first or last name, return the most likely correct real human name.\n\nSpecial rules:\n- Irish/Gaelic names: O'Brien, O'Connor, O'Sullivan, Murphy, Saoirse, Siobhan\n- Indian names: Garikapati, Abhinaya, Venkataraman, Krishnamurthy\n- Hispanic names with hyphens: Garcia-Ramirez, Lopez-Hernandez\n- Scottish prefixes: McDonald, McCarthy, McAllister\n- Numbers that sound like names: Fourteen→Patel, Fortin→Fortin, Eighteen→Stein\n\nOutput ONLY valid JSON. No markdown. No explanation.\nFormat: {\"corrected_name\": \"Name\", \"confidence\": \"high\" or \"low\"}\nIf you cannot determine a real name with confidence, return: {\"corrected_name\": \"\", \"confidence\": \"low\"}"
    },
    {
      "role": "user",
      "content": "ASR heard: \"{{ $json.body.asr_text }}\". Name type: {{ $json.body.name_type }}. What is the correct name?"
    }
  ]
}

parameters.jsCode:
// Get Mistral's response
const mistralOutput = $input.first().json;
let content = mistralOutput.choices[0].message.content;

// Remove markdown code blocks if present
content = content.replace(/```json\n?/g, '');
content = content.replace(/```\n?/g, '');
content = content.trim();

// Parse the JSON
let parsedContent;
try {
  parsedContent = JSON.parse(content);
} catch (e) {
  parsedContent = { corrected_name: null, confidence: "low" };
}

// Return the cleaned data for the IF node
return [{
  json: {
    corrected_name: parsedContent.corrected_name,
    confidence: parsedContent.confidence
  }
}];

// Get the corrected name from the HTTP Request node
const httpResponse = $node["HTTP Request"].json;
const content = httpResponse.choices[0].message.content;

// Parse the JSON from Mistral
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = { corrected_name: null, confidence: "low" };
}

// Return the formatted response for Retell
return [{
  json: {
    action: "confirm",
    suggested_name: parsed.corrected_name
  }
}];
